// // This module selects between two 8-bit inputs based on the 'sel' signal. When 'sel' is high (1), the output reflects the value of 'out1'; when 'sel' is low (0), the output takes the value of 'out2'.
module top_module(
    input sel,
    input [7:0] out1,
    input [7:0] out2,
    output reg [7:0] out
);always @(*) begin
    if(sel == 0)
        out = out1;
    else
        out = out2;
end

endmodule
